  @protected
  void sse_encode_list_trusted_peer(
      List<TrustedPeer> self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    sse_encode_i_32(self.length, serializer);
    for (final item in self) {
      sse_encode_trusted_peer(item, serializer);
    }
  }

  @protected
  void sse_encode_peer(Peer self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    sse_encode_String(self.deviceId, serializer);
    sse_encode_String(self.deviceName, serializer);
    sse_encode_String(self.ipAddress, serializer);
    sse_encode_u_16(self.wsPort, serializer);
    sse_encode_u_64(self.lastSeen, serializer);
    sse_encode_String(self.connectionStatus, serializer);
  }

  @protected
  void sse_encode_sync_event(SyncEvent self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    switch (self) {
      case SyncEvent_ClipboardUpdated(content: final content):
        sse_encode_i_32(0, serializer);
        sse_encode_String(content, serializer);
      case SyncEvent_ConnectionStatus(
          connected: final connected,
          message: final message
        ):
        sse_encode_i_32(1, serializer);
        sse_encode_bool(connected, serializer);
        sse_encode_String(message, serializer);
      case SyncEvent_Error(message: final message):
        sse_encode_i_32(2, serializer);
        sse_encode_String(message, serializer);
    }
  }

  @protected
  void sse_encode_trusted_peer(TrustedPeer self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    sse_encode_String(self.deviceId, serializer);
    sse_encode_String(self.deviceName, serializer);
    sse_encode_String(self.fingerprint, serializer);
    sse_encode_u_64(self.pairedAt, serializer);
  }

